import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import styled from 'styled-components';
import ThemeToggle from './ThemeToggle';

const Nav = styled.nav`
  /* Copy navbar styles from original styles.css */
  position: fixed;
  width: 100%;
  z-index: 1000;
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(10px);
`;

const Container = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 10%;
`;

const Logo = styled.span`
  font-family: 'Orbitron', sans-serif;
  font-size: 1.5rem;
  color: #00FFFF;
`;

const NavLinks = styled.ul`
  display: flex;
  gap: 2rem;
  list-style: none;

  @media (max-width: 768px) {
    display: none;
  }
`;

const NavLink = styled(Link)`
  color: white;
  text-decoration: none;
  font-weight: 500;
  transition: color 0.3s ease;

  &:hover {
    color: #00FFFF;
  }
`;

const JoinButton = styled.button`
  background: none;
  border: none;
  margin-left: auto;

  a {
    color: #00FFFF;
    text-decoration: none;
    padding: 8px 20px;
    border: 2px solid #00FFFF;
    border-radius: 25px;
    transition: all 0.3s ease;

    &:hover {
      background: #00FFFF;
      color: #000;
    }
  }
`;

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <Nav>
      <Container>
        <img src={require('../assets/symbol.png')} alt="logo" />
        <NavLinks className="left-links">
          <li><NavLink to="/team">TEAM</NavLink></li>
          <li><NavLink to="/gallery">GALLERY</NavLink></li>
        </NavLinks>
        <Logo>OPTIMUS</Logo>
        <NavLinks className="right-links">
          <li><NavLink to="/events">EVENT</NavLink></li>
          <li><NavLink to="#footer">CONTACT</NavLink></li>
        </NavLinks>        
        <JoinButton>
          <a href="https://github.com/optimusorgz" target="_blank" rel="noopener noreferrer" id="dynamic-link">Join us</a>
        </JoinButton>
      </Container>
      <ThemeToggle />
    </Nav>
  );
};

export default Navbar;
